mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rnum, A.* FROM ( SELECT F.festival_id, F.description, F.start_date, F.end_date, F.status, P.name, P.place_type, P.address, P.view_count, P.latitude, P.longitude, P.image_url, P.created_at
FROM FESTIVAL F LEFT JOIN PLACE P ON F.festival_id = P.place_id AND P.place_type = 'FEST'
(P.Name LIKE '%'||#{keyword}||'%' OR P.ADDRESS LIKE '%'||#{keyword}||'%' OR F.DESCRIPTION LIKE '%'||#{keyword}||'%')
AND F.status IN
#{item}
ORDER BY
P.created_at DESC F.start_date ASC F.start_date DESC F.end_date ASC F.end_date DESC F.status ASC P.created_at DESC
) A ) WHERE rnum BETWEEN #{startRow} AND #{endRow}

mapper.update:
UPDATE FESTIVAL
SET
    description = #{description, jdbcType=CLOB},
    start_date = #{start_date},
    end_date = #{end_date}
WHERE festival_id = #{festival_id}

UPDATE FESTIVAL_TICKET
SET
    price = #{price},
    stock = #{stock},
    description = #{description, jdbcType=CLOB}
WHERE festival_id = #{festival_id}
AND ticket_type = #{ticket_type}

mapper.select:
SELECT place_id
FROM PLACE
WHERE name = #{name}
AND address = #{address}
